import{c as e,Q as t,j as s,m as o}from"./chunks/framework.BPKcPtvA.js";const u=JSON.parse('{"title":"Claude Code 缓存优化代理","description":"","frontmatter":{},"headers":[],"relativePath":"cli/5-cache-fix.md","filePath":"cli/5-cache-fix.md","lastUpdated":1779937099000}'),d={name:"cli/5-cache-fix.md"};function i(n,a,l,r,c,p){return t(),s("div",null,[...a[0]||(a[0]=[o(`<h1 id="claude-code-缓存优化代理" tabindex="-1">Claude Code 缓存优化代理 <a class="header-anchor" href="#claude-code-缓存优化代理" aria-label="Permalink to &quot;Claude Code 缓存优化代理&quot;">​</a></h1><hr><h2 id="一句话介绍" tabindex="-1">一句话介绍 <a class="header-anchor" href="#一句话介绍" aria-label="Permalink to &quot;一句话介绍&quot;">​</a></h2><p><a href="https://forward.apiapi.site/https://github.com/cnighswonger/claude-code-cache-fix" target="_blank" rel="noreferrer">claude-code-cache-fix</a><br> 是一个<strong>第三方开源小工具</strong> ，作用是帮 Claude Code <strong>省额度</strong> 。</p><p>简单理解：它像一个“中间人”，挡在你的电脑和 Claude 服务器之间，<br> 帮你把每次发出去的请求“整理整齐”，让 Claude 更容易<strong>复用之前的对话</strong><br> （也就是<strong>命中缓存</strong> ），从而少花额度。</p><blockquote><p>它不会让 AI 变聪明，只是让你的额度更耐用。</p></blockquote><h2 id="为什么需要它" tabindex="-1">为什么需要它？ <a class="header-anchor" href="#为什么需要它" aria-label="Permalink to &quot;为什么需要它？&quot;">​</a></h2><p>Claude Code 用得越久，你可能会发现：</p><ul><li>同样几句话，<strong>额度掉得比想象中快</strong> ；</li><li>恢复一个旧对话（<code>--resume</code>），<strong>像重新付了一次费</strong> ；</li><li>开了 MCP、Skills、Hooks 后，<strong>消耗莫名变高</strong> 。</li></ul><p>这些大多不是 bug，而是 Claude Code 的请求结构有点“不稳定”，<br> 导致服务器认不出“这是同一段上下文”，于是<strong>重新计费</strong> 。</p><p><code>claude-code-cache-fix</code> 干的事情就一件：<strong>把请求洗干净、排好序、<br> 打上正确的缓存标记</strong>，让 Claude 服务器一眼认出“这段我见过”，<br> 直接走便宜的缓存价。</p><p>它具体做了什么（看不懂可以跳过）：</p><table tabindex="0"><thead><tr><th>它做的事</th><th>对你的好处</th></tr></thead><tbody><tr><td>修正恢复会话时的请求结构</td><td><code>--resume</code> 后不再被当成新对话重新计费</td></tr><tr><td>去掉版本号等不稳定标记</td><td>Claude Code 升级后缓存不会突然失效</td></tr><tr><td>把工具、MCP 定义按固定顺序排列</td><td>同样的配置每次请求长得一样，缓存能命中</td></tr><tr><td>自动打好 <code>cache_control</code> 标记</td><td>主动告诉服务器“这段请缓存”</td></tr><tr><td>记录每次缓存命中和额度情况</td><td>出问题时方便排查，文件存在 <code>~/.claude/quota-status/</code></td></tr><tr><td>不依赖老的 <code>NODE_OPTIONS</code> 注入</td><td>新版 Bun 版 Claude Code 也能用</td></tr></tbody></table><h2 id="适合谁用" tabindex="-1">适合谁用？ <a class="header-anchor" href="#适合谁用" aria-label="Permalink to &quot;适合谁用？&quot;">​</a></h2><ul><li>✅ 重度使用 Claude Code、对额度敏感的用户</li><li>✅ 经常 <code>--resume</code> 长会话、开了一堆 MCP / Skills 的用户</li><li>✅ 愿意动一点命令行的用户</li><li>❌ 完全不想碰终端、只想开箱即用的用户（先不用上这个）</li></ul><p>它不能解决所有额度问题</p><p>这个工具只能优化本地请求结构和缓存相关问题。模型本身价格、长上下文消耗、<br> 服务端配额降级、错误模型选择、频繁大文件读取等问题，仍然需要单独排查。</p><p>Windows 原生环境不适用</p><p><code>claude-code-cache-fix</code> <strong>不建议在 Windows 原生 CMD / PowerShell 中配置使用</strong> 。</p><p>Windows 用户请优先在 <strong>WSL 的 Linux 环境</strong> 中完成 Node.js、Claude Code、<br> Suirenai 和 <code>claude-code-cache-fix</code> 的整套配置。不要把 Windows 原生<br> Claude Code 与 WSL 代理混在一起使用，否则很容易出现路径、环境变量、<br> 后台服务和本地端口不一致的问题。</p><p>第三方工具提醒</p><p><code>claude-code-cache-fix</code> 不是 Suirenai 官方维护工具。它会经过本机 API 请求，<br> 安装前请自行审查源码、依赖和配置方式。</p><h2 id="推荐使用-ai-辅助配置" tabindex="-1">推荐使用 AI 辅助配置 <a class="header-anchor" href="#推荐使用-ai-辅助配置" aria-label="Permalink to &quot;推荐使用 AI 辅助配置&quot;">​</a></h2><p>这个工具涉及本地代理、环境变量和后台服务配置，手动配置容易漏项。<br> 推荐把你的系统环境、Suirenai Endpoint 和 GitHub 项目链接一起发给 AI，<br> 让 AI 按你的机器生成命令。</p><p>可以直接使用下面这段提示词：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>请根据 https://forward.apiapi.site/https://github.com/cnighswonger/claude-code-cache-fix 的最新 README，</span></span>
<span class="line"><span>    帮我在当前系统中配置 Claude Code 缓存优化代理。</span></span>
<span class="line"><span>    要求：</span></span>
<span class="line"><span>    1. 我使用 Suirenai，upstream 必须是 https://api.suirenai.com</span></span>
<span class="line"><span>    2. Claude Code 的 ANTHROPIC_BASE_URL 应指向本地代理 http://127.0.0.1:9801</span></span>
<span class="line"><span>    3. 保留 ANTHROPIC_AUTH_TOKEN，用我的 Suirenai CC 分组密钥替换</span></span>
<span class="line"><span>    4. Windows 用户请按 WSL Linux 环境来配置，不要使用 Windows 原生 CMD / PowerShell</span></span>
<span class="line"><span>    5. 给出验证代理健康状态和 Claude Code 回复是否正常的命令</span></span>
<span class="line"><span>    6. 长期使用时，请给出适合当前系统的后台服务配置方式</span></span></code></pre></div><h2 id="最小验证流程" tabindex="-1">最小验证流程 <a class="header-anchor" href="#最小验证流程" aria-label="Permalink to &quot;最小验证流程&quot;">​</a></h2><p>下面的命令适合在 Linux / macOS / WSL 中先验证代理是否能跑通：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -g</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> claude-code-cache-fix</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">CACHE_FIX_PROXY_UPSTREAM</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">https://api.suirenai.com</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> cache-fix-proxy</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> server</span></span></code></pre></div><h2 id="配置-claude-code" tabindex="-1">配置 Claude Code <a class="header-anchor" href="#配置-claude-code" aria-label="Permalink to &quot;配置 Claude Code&quot;">​</a></h2><p>代理启动后，将 Claude Code 的 <code>settings.json</code> 中 <code>ANTHROPIC_BASE_URL</code><br> 改为本地代理地址，<code>ANTHROPIC_AUTH_TOKEN</code> 继续填写你的 Suirenai<br><strong>CC</strong> 分组密钥：</p><pre><code>{
  &quot;env&quot;: {
    &quot;ANTHROPIC_BASE_URL&quot;: &quot;http://127.0.0.1:9801&quot;,
    &quot;ANTHROPIC_AUTH_TOKEN&quot;: &quot;xxx&quot;,
    &quot;CLAUDE_CODE_ATTRIBUTION_HEADER&quot;: &quot;0&quot;,
    &quot;CLAUDE_CODE_DISABLE_NONESSENTIAL_TRAFFIC&quot;: &quot;1&quot;,
    &quot;CLAUDE_CODE_DISABLE_TERMINAL_TITLE&quot;: &quot;1&quot;
  }
}
</code></pre><h2 id="验证代理" tabindex="-1">验证代理 <a class="header-anchor" href="#验证代理" aria-label="Permalink to &quot;验证代理&quot;">​</a></h2><p>另开一个终端，检查代理健康状态：</p><pre><code>curl http://127.0.0.1:9801/health
</code></pre><p>如果返回 <code>{&quot;status&quot;:&quot;ok&quot;}</code>，再重新打开终端运行：</p><pre><code>claude
</code></pre><p>能正常进入 Claude Code 并收到回复，说明代理和 Suirenai 配置已经连通。</p><h2 id="长期使用建议" tabindex="-1">长期使用建议 <a class="header-anchor" href="#长期使用建议" aria-label="Permalink to &quot;长期使用建议&quot;">​</a></h2><p>手动启动代理只适合临时验证。长期使用时，建议继续让 AI 根据你的系统生成<br><code>systemd</code>、<code>launchd</code> 或其它后台服务配置，避免每次使用 Claude Code 前都要<br> 手动启动代理。</p><p>再次提醒：Windows 用户请在 WSL 里完成整套配置，不要使用 Windows 原生<br> CMD / PowerShell 作为运行环境。</p>`,41)])])}const C=e(d,[["render",i]]);export{u as __pageData,C as default};
